// Extraer información del mensaje entrante
const input = $input.first().json;

// Extraer datos del mensaje
let phoneNumber = '';
let messageText = '';
let messageType = 'texto';
let userName = 'Cliente';

// Si es un mensaje de WhatsApp
if (input.data && input.data.key) {
  phoneNumber = input.data.key.remoteJid.replace('@s.whatsapp.net', '');

  if (input.data.message.conversation) {
    messageText = input.data.message.conversation;
  } else if (input.data.message.extendedTextMessage) {
    messageText = input.data.message.extendedTextMessage.text;
  } else if (input.data.message.imageMessage) {
    messageText = 'Imagen recibida';
    messageType = 'imagen';
  }
} else {
  // Si es una llamada directa al webhook
  phoneNumber = input.phone || 'sistema';
  messageText = input.message || 'hola';
  userName = input.name || 'Usuario';
}

// Detectar comandos
const text = messageText.toLowerCase();
let command = 'bienvenida';

if (text.includes('catalogo') || text.includes('productos')) {
  command = 'catalogo';
} else if (text.includes('venta') || text.includes('cotizar')) {
  command = 'venta';
} else if (text.includes('precio') || text.includes('costo')) {
  command = 'precios';
} else if (text.includes('ayuda') || text.includes('servicios')) {
  command = 'ayuda';
} else if (text.includes('estado') || text.includes('sistema')) {
  command = 'estado';
}

return {
  phoneNumber,
  messageText,
  messageType,
  userName,
  command,
  timestamp: new Date().toISOString()
};

// Generar mensaje de bienvenida
const userName = $('Procesar Mensaje').item.json.userName;
const phoneNumber = $('Procesar Mensaje').item.json.phoneNumber;

const welcomeMessage = `🎨 *¡Bienvenido a Media Quality Net!* 🎨

Hola ${userName}, soy tu asistente virtual de MQN.

*Nuestros servicios:*
• 🖼️ Impresión digital de alta calidad
• 👕 Serigrafía y sublimación
• 🎯 Productos personalizados
• 📱 Atención multicanal

*Comandos disponibles:*
• "catalogo" - Ver productos
• "venta" - Crear cotización
• "precios" - Consultar tarifas
• "ayuda" - Más información
• "estado" - Estado del sistema

*Contacto:*
📞 WhatsApp: ${phoneNumber}
🏢 Horario: Lunes a Viernes 9:00-18:00

¿En qué puedo ayudarte hoy? 😊`;

return {
  message: welcomeMessage,
  phoneNumber,
  timestamp: new Date().toISOString()
};

// Verificar estado del sistema
const systemStatus = {
  servicios: {
    n8n: '✅ Activo',
    postgres: '✅ Activo',
    redis: '✅ Activo',
    evolution_api: '✅ Activo'
  },
  workflows: {
    bienvenida: '✅ Activo',
    whatsapp_handler: '✅ Activo',
    catalogador_visual: '✅ Activo'
  },
  ultima_actualizacion: new Date().toISOString()
};

const statusMessage = `📊 *Estado del Sistema MQN* 📊

*Servicios:*
${Object.entries(systemStatus.servicios).map(([key, value]) => `• ${key}: ${value}`).join('\n')}

*Workflows:*
${Object.entries(systemStatus.workflows).map(([key, value]) => `• ${key}: ${value}`).join('\n')}

*Última actualización:*
${new Date(systemStatus.ultima_actualizacion).toLocaleString('es-MX')}

🎯 *Sistema operativo al 100%*`;

return {
  message: statusMessage,
  phoneNumber: $('Procesar Mensaje').item.json.phoneNumber,
  timestamp: new Date().toISOString()
};

// Log del sistema
const logEntry = {
  timestamp: new Date().toISOString(),
  evento: 'bienvenida_mqn',
  usuario: $('Procesar Mensaje').item.json.userName,
  telefono: $('Procesar Mensaje').item.json.phoneNumber,
  comando: $('Procesar Mensaje').item.json.command,
  respuesta: 'enviada',
  estado: 'exitoso'
};

console.log('MQN Bienvenida:', JSON.stringify(logEntry, null, 2));

return logEntry;
